#!/bin/bash
# AI-GENERATED CONTENT — Generated by AI systems under human editorial direction.
#
# Save ensemble state to a snapshot directory.
# Preserves state_record.bin, mesh_knowledge.bin, epistate_record.bin
# for all cognitive entities. Timekeepers excluded.
#
# Usage:
#   ./ops/save-state.sh [SNAPSHOT_NAME]
#
# Examples:
#   ./ops/save-state.sh session30         # saves to snapshots/session30/
#   ./ops/save-state.sh                   # saves to snapshots/YYYY-MM-DD-HHMMSS/

set -euo pipefail

MESH="${SAIOS_MESH_DIR:-/opt/saios/mesh}"
SNAP_DIR="${MESH}/../snapshots"
NAME="${1:-$(date +%Y-%m-%d-%H%M%S)}"
DEST="$SNAP_DIR/$NAME"

mkdir -p "$DEST"

count=0
for dir in "$MESH"/founder-* "$MESH"/derived-* "$MESH"/emergent-*; do
    [[ -d "$dir" ]] || continue
    name=$(basename "$dir")
    entity_snap="$DEST/$name"
    mkdir -p "$entity_snap"

    for f in state_record.bin mesh_knowledge.bin epistate_record.bin sluice.bin; do
        [[ -f "$dir/$f" ]] && cp "$dir/$f" "$entity_snap/$f"
    done
    count=$((count + 1))
done

echo "Saved $count entities to $DEST"
ls "$DEST"
